#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int flag = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] - 1 < N && A[A[i] - 1] != A[i] && A[A[i] - 1] == A[A[A[i] - 1] - 1]) {
                flag = 1;
                break;
            }
        }
        if (flag) {
            printf("Truly Happy\n");
        } else {
            printf("Poor Chef\n");
        }
    }
    return 0;
}

