import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            boolean flag = false;
            for (int i = 0; i < N; i++) {
                if (A[i] - 1 < N && A[A[i] - 1] != A[i] && A[A[i] - 1] == A[A[A[i] - 1] - 1]) {
                    flag = true;
                    break;
                }
            }
            if (flag) {
                System.out.println("Truly Happy");
            } else {
                System.out.println("Poor Chef");
            }
        }
    }
}

